#include <bits/stdc++.h>
using namespace std;
const int N=11,M=1<<10;
int n,m,g[105],dp[2][M][M];
vector<int> v;
int cnt[M];
bool check(int x)
{
    for(int i=0;i<m;i++)
    {
        if(((x>>i)&1)&&(((x>>(i+1))&1)||((x>>(i+2))&1))) return 0;
    }
    return 1;
}
int count(int x)
{
    int res=0;
    for(int i=0;i<m;i++) res+=(x>>i)&1;
    return res;
}
int main()
{
    cin>>n>>m;
    for(int i=1;i<=n;i++)
    {
        for(int j=0;j<m;j++)
        {
            char s;
            cin>>s;
            if(s=='H') g[i]+=(1<<j);
        }
    }
    for(int i=0;i<(1<<m);i++)
    {
        if(check(i)) v.push_back(i);
        cnt[i]=count(i);
    }
    for(int i=1;i<=n+2;i++)
    {
        for(int j=0;j<v.size();j++)
        {
            for(int k=0;k<v.size();k++)
            {
                for(int u=0;u<v.size();u++)
                {
                    int a=v[j],b=v[k],c=v[u];
                    if((a&b)|(b&c)|(a&c)) continue;
                    if((g[i-1]&a)||(g[i]&b)) continue;
                    dp[i%2][j][k]=max(dp[i%2][j][k],dp[(i-1)%2][u][j]+cnt[b]);
                }
            }
        }
    }
    cout<<dp[(n+2)%2][0][0];
    return 0;
}
